package main

import (
    "crypto/tls"
    "fmt"
    "io/ioutil"
    "os"
)

// Compliant: Secure secret management

// GOOD: AWS credentials from environment or IAM roles
func setupAWS() (*aws.Config, error) {
    // Use AWS credential chain (environment, IAM roles, etc.)
    config := &aws.Config{
        Region: aws.String(os.Getenv("AWS_REGION")),
    }

    // AWS SDK automatically handles credentials from:
    // 1. Environment variables (AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY)
    // 2. IAM roles (for EC2/Lambda)
    // 3. ~/.aws/credentials file
    // 4. IAM roles for service accounts (EKS)

    return config, nil
}

// GOOD: API tokens from environment
func getAPICredentials() (string, string, error) {
    githubToken := os.Getenv("GITHUB_TOKEN")
    slackWebhook := os.Getenv("SLACK_WEBHOOK_URL")

    if githubToken == "" {
        return "", "", fmt.Errorf("GitHub token not configured")
    }
    if slackWebhook == "" {
        return "", "", fmt.Errorf("Slack webhook not configured")
    }

    return githubToken, slackWebhook, nil
}

// GOOD: Stripe configuration
func getStripeConfig() (string, error) {
    secretKey := os.Getenv("STRIPE_SECRET_KEY")
    if secretKey == "" {
        return "", fmt.Errorf("Stripe secret key not configured")
    }
    return secretKey, nil
}

// GOOD: Database connection from environment
func connectToMongoDB() (string, error) {
    username := os.Getenv("MONGODB_USERNAME")
    password := os.Getenv("MONGODB_PASSWORD")
    host := os.Getenv("MONGODB_HOST")
    database := os.Getenv("MONGODB_DATABASE")

    if username == "" || password == "" || host == "" {
        return "", fmt.Errorf("MongoDB credentials not configured")
    }

    connectionURI := fmt.Sprintf("mongodb://%s:%s@%s/%s", username, password, host, database)
    return connectionURI, nil
}

// GOOD: JWT key from file or environment
func getJWTSigningKey() ([]byte, error) {
    keyPath := os.Getenv("JWT_KEY_FILE")
    if keyPath != "" {
        // Read from secure file
        return ioutil.ReadFile(keyPath)
    }

    keyEnv := os.Getenv("JWT_SECRET")
    if keyEnv == "" {
        return nil, fmt.Errorf("JWT signing key not configured")
    }

    return []byte(keyEnv), nil
}

