// GOOD: Service credentials configuration
type ServiceCredentials struct {
    TwilioSID    string
    TwilioToken  string
    SendGridKey  string
    FirebaseKey  string
}

func loadServiceCredentials() (*ServiceCredentials, error) {
    creds := &ServiceCredentials{
        TwilioSID:   os.Getenv("TWILIO_ACCOUNT_SID"),
        TwilioToken: os.Getenv("TWILIO_AUTH_TOKEN"),
        SendGridKey: os.Getenv("SENDGRID_API_KEY"),
        FirebaseKey: os.Getenv("FIREBASE_API_KEY"),
    }

    if err := creds.Validate(); err != nil {
        return nil, err
    }

    return creds, nil
}

func (c *ServiceCredentials) Validate() error {
    if c.TwilioSID == "" || c.TwilioToken == "" {
        return fmt.Errorf("Twilio credentials not configured")
    }
    return nil
}

// GOOD: TLS certificates from files
func loadTLSConfig() (*tls.Config, error) {
    certFile := os.Getenv("TLS_CERT_FILE")
    keyFile := os.Getenv("TLS_KEY_FILE")

    if certFile == "" || keyFile == "" {
        return nil, fmt.Errorf("TLS certificate files not configured")
    }

    cert, err := tls.LoadX509KeyPair(certFile, keyFile)
    if err != nil {
        return nil, fmt.Errorf("failed to load TLS certificate: %w", err)
    }

    return &tls.Config{
        Certificates: []tls.Certificate{cert},
        MinVersion:   tls.VersionTLS12,
    }, nil
}

